 1	import * as React from 'react';
 2	import {
 3	  ResourceLink,
 4	  K8sResourceCommon,
 5	  OwnerReference,
 6	} from '@openshift-console/dynamic-plugin-sdk';
 7	import { TFunction } from 'react-i18next';
 8	import { Trans } from 'react-i18next';
 9	import {
10	  Button,
11	  Modal,
12	  ModalVariant,
13	  ButtonVariant,
14	} from '@patternfly/react-core';
15	import { ExclamationTriangleIcon } from '@patternfly/react-icons';
16	import { useCustomTranslation } from '../useCustomTranslationHook';
17	import { referenceForOwnerRef } from '../utils';
18	import { ModalBody, ModalFooter, ModalHeader, CommonModalProps } from './Modal';
19	
20	const header = (t: TFunction) => (
21	  <ModalHeader>
22	    <ExclamationTriangleIcon
23	      color="var(--pf-t--global--color--status--warning--default)"
24	      className="icon--spacer"
25	    />
26	    {t('Managed resource')}
27	  </ModalHeader>
28	);
29	
30	const ManagedResourceSaveModal: React.FC<ManagedResourceSaveModalProps> = ({
31	  closeModal,
32	  isOpen,
33	  extraProps: { onSubmit, resource, owner },
34	}) => {
35	  const submit = (event) => {
36	    event.preventDefault();
37	    onSubmit();
38	    closeModal();
39	  };
40	
41	  const { t } = useCustomTranslation();
42	  return (
43	    <Modal
44	      position="top"
45	      variant={ModalVariant.small}
46	      header={header(t)}
47	      isOpen={isOpen}
48	      onClose={closeModal}
49	      showClose={false}
50	      hasNoBodyWrapper={true}
51	    >
52	      <ModalBody>
53	        <Trans t={t}>
54	          This resource is managed by{' '}
55	          <ResourceLink
56	            className="modal__inline-resource-link"
57	            inline
58	            kind={referenceForOwnerRef(owner)}
59	            name={owner.name}
60	            namespace={resource.metadata.namespace}
61	          />{' '}
62	          and any modifications may be overwritten. Edit the managing resource
63	          to preserve changes.
64	        </Trans>
65	      </ModalBody>
66	      <ModalFooter>
67	        <Button key="Save" variant={ButtonVariant.primary} onClick={submit}>
68	          {t('Save')}
69	        </Button>
70	      </ModalFooter>
71	    </Modal>
72	  );
73	};
74	
75	type ManagedResourceSaveModalProps = {
76	  extraProps: {
77	    onSubmit: () => void;
78	    resource: K8sResourceCommon;
79	    owner: OwnerReference;
80	  };
81	} & CommonModalProps;
82	
83	export default ManagedResourceSaveModal;

